/**
 * Manual decoding of the failed transaction calldata to extract Escrow ID
 *
 * From the transaction: 0xb6649d581a3f908fc0d51731beefbf8bc836a52769184d7fe96b46255d053012
 */

// The raw calldata (from the output above)
const fullCalldata = ``;

console.log('🔍 Manual Calldata Decoding\n');
console.log('═'.repeat(80));

// Find the pattern: c4333f84f5034d8691cb95f068def2e3b6dc60fa (Escrow contract)
const escrowContractHex = 'c4333f84f5034d8691cb95f068def2e3b6dc60fa';
const escrowIndex = fullCalldata.toLowerCase().indexOf(escrowContractHex);

if (escrowIndex === -1) {
  console.log('❌ Escrow contract address not found in calldata');
  process.exit(1);
}

console.log(`✅ Found Escrow contract at position ${escrowIndex / 2} bytes`);

// After escrow contract address, we should have:
// - padding zeros (to align to 32 bytes)
// - function selector (4 bytes = 8 hex chars)
// - escrowId (bytes32 = 64 hex chars)
// - recipient address (address = 40 hex chars with padding)

const afterEscrowContract = fullCalldata.slice(escrowIndex + escrowContractHex.length);
console.log(`\nData after escrow contract address:`);
console.log(afterEscrowContract.slice(0, 200) + '...');

// Find 4679e667 (redeemAndUnwrap selector)
const redeemSelector = '4679e667';
const redeemIndex = afterEscrowContract.indexOf(redeemSelector);

if (redeemIndex === -1) {
  console.log('\n❌ redeemAndUnwrap selector not found');
  process.exit(1);
}

console.log(`\n✅ Found redeemAndUnwrap selector at offset ${redeemIndex / 2} bytes`);

// After selector, next 64 hex chars should be escrowId (bytes32)
const afterSelector = afterEscrowContract.slice(redeemIndex + redeemSelector.length);
console.log(`\nData after selector (first 160 chars):`);
console.log(afterSelector.slice(0, 160));

// Extract escrowId (bytes32 = 64 hex chars)
const escrowIdHex = afterSelector.slice(0, 64);
const escrowId = '0x' + escrowIdHex;

console.log(`\n🎯 ESCROW ID EXTRACTED!`);
console.log('═'.repeat(80));
console.log(`Escrow ID: ${escrowId}`);
console.log(`As decimal: ${BigInt(escrowId).toString()}`);

// Extract recipient (next 64 hex chars, but only last 40 are address)
const recipientPadded = afterSelector.slice(64, 128);
const recipientHex = '0x' + recipientPadded.slice(24); // Remove padding
console.log(`Recipient: ${recipientHex}`);

console.log(`\n✅ Decoded redeemAndUnwrap parameters:`);
console.log(`   escrowId:  ${escrowId}`);
console.log(`   recipient: ${recipientHex}`);

console.log(`\n📋 To debug this escrow, run:`);
console.log(`   ESCROW_ID=${escrowId} npx tsx debug-escrow-state.ts`);
